import { existsSync, readFileSync, statSync } from "node:fs";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

const projectRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const requiredFiles = ["main.js", "manifest.json", "styles.css"];
const optionalReleaseFiles = ["versions.json"];
const errors = [];

function readJson(relativePath) {
  const absolutePath = path.join(projectRoot, relativePath);
  try {
    return JSON.parse(readFileSync(absolutePath, "utf8"));
  } catch (error) {
    errors.push(`${relativePath} is not valid JSON: ${error instanceof Error ? error.message : String(error)}`);
    return undefined;
  }
}

function assertFileExists(relativePath) {
  const absolutePath = path.join(projectRoot, relativePath);
  if (!existsSync(absolutePath)) {
    errors.push(`${relativePath} is missing`);
    return;
  }

  const stats = statSync(absolutePath);
  if (!stats.isFile()) {
    errors.push(`${relativePath} is not a file`);
    return;
  }

  if (stats.size <= 0) {
    errors.push(`${relativePath} is empty`);
  }
}

for (const relativePath of [...requiredFiles, ...optionalReleaseFiles]) {
  assertFileExists(relativePath);
}

const manifest = readJson("manifest.json");
const packageJson = readJson("package.json");
const versions = readJson("versions.json");

if (manifest && packageJson) {
  if (manifest.id !== packageJson.name) {
    errors.push(`manifest.json id (${manifest.id}) does not match package.json name (${packageJson.name})`);
  }

  if (manifest.version !== packageJson.version) {
    errors.push(`manifest.json version (${manifest.version}) does not match package.json version (${packageJson.version})`);
  }

  if (packageJson.main !== "main.js") {
    errors.push(`package.json main must be main.js, got ${packageJson.main}`);
  }
}

if (manifest && versions) {
  const minAppVersion = versions[manifest.version];
  if (!minAppVersion) {
    errors.push(`versions.json does not contain current manifest version ${manifest.version}`);
  } else if (minAppVersion !== manifest.minAppVersion) {
    errors.push(
      `versions.json min app version (${minAppVersion}) does not match manifest minAppVersion (${manifest.minAppVersion})`
    );
  }
}

const mainJsPath = path.join(projectRoot, "main.js");
if (existsSync(mainJsPath)) {
  const mainJs = readFileSync(mainJsPath, "utf8");
  if (!mainJs.startsWith("/* THIS IS A GENERATED/BUNDLED FILE BY ESBUILD.")) {
    errors.push("main.js does not start with the expected esbuild banner");
  }

  if (mainJs.includes("sourceMappingURL=")) {
    errors.push("main.js contains a sourceMappingURL marker; production release artifacts should not include sourcemaps");
  }
}

const stylesPath = path.join(projectRoot, "styles.css");
if (existsSync(stylesPath)) {
  const styles = readFileSync(stylesPath, "utf8");
  if (!styles.includes("note-loom-")) {
    errors.push("styles.css does not contain Note Loom plugin styles");
  }
}

if (errors.length > 0) {
  console.error("Release artifact check failed.");
  for (const error of errors) {
    console.error(`- ${error}`);
  }
  process.exit(1);
}

console.log(
  `Release artifact check passed. Required plugin files: ${requiredFiles.join(", ")}. Version: ${manifest?.version ?? "unknown"}.`
);
